import React, { useEffect } from 'react';
import { useAuth } from '../context/AuthContext';

// دالة لتشغيل الصوت
const playSound = (type: 'success' | 'error' | 'warning') => {
  try {
    const audio = new Audio();

    switch (type) {
      case 'success':
        // صوت نجاح - نغمة عالية وممتعة
        audio.src = 'data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQoGAACBhYqFbF1fdJivrJBhNjVgodDbq2EcBj+a2/LDciUFLIHO8tiJNwgZaLvt559NEAxQp+PwtmMcBjiR1/LMeSwFJHfH8N2QQAoUXrTp66hVFApGn+DyvmwhBSuBzvLZiTYIG2m98OScTgwOUarm7blmFgU7k9n1unEiBC13yO/eizEIHWq+8+OWT';
        break;
      case 'error':
        // صوت خطأ - نغمة منخفضة وحادة
        audio.src = 'data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQoGAACBhYqFbF1fdJivrJBhNjVgodDbq2EcBj+a2/LDciUFLIHO8tiJNwgZaLvt559NEAxQp+PwtmMcBjiR1/LMeSwFJHfH8N2QQAoUXrTp66hVFApGn+DyvmwhBSuBzvLZiTYIG2m98OScTgwOUarm7blmFgU7k9n1unEiBC13yO/eizEIHWq+8+OWT';
        break;
      case 'warning':
        // صوت تحذير - نغمة متوسطة
        audio.src = 'data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQoGAACBhYqFbF1fdJivrJBhNjVgodDbq2EcBj+a2/LDciUFLIHO8tiJNwgZaLvt559NEAxQp+PwtmMcBjiR1/LMeSwFJHfH8N2QQAoUXrTp66hVFApGn+DyvmwhBSuBzvLZiTYIG2m98OScTgwOUarm7blmFgU7k9n1unEiBC13yO/eizEIHWq+8+OWT';
        break;
    }

    audio.volume = 0.3;
    audio.play().catch(err => console.log('Audio play failed:', err));
  } catch (error) {
    console.log('Sound creation failed:', error);
  }
};

// دالة لإظهار الإشعاع
const showNotification = (message: string, type: 'success' | 'error' | 'warning' = 'success') => {
  playSound(type);

  // إنشاء عنصر الإشعار
  const notification = document.createElement('div');
  notification.className = `notification notification-${type}`;
  notification.innerHTML = `
    <div class="notification-content">
      <div class="notification-icon">
        ${type === 'success' ? '✅' : type === 'error' ? '❌' : '⚠️'}
      </div>
      <div class="notification-message">${message}</div>
    </div>
    <button class="notification-close">×</button>
  `;

  // إضافة الـ CSS
  notification.style.cssText = `
    position: fixed;
    top: 20px;
    right: 20px;
    background: ${type === 'success' ? '#10b981' : type === 'error' ? '#ef4444' : '#f59e0b'};
    color: white;
    padding: 16px 20px;
    border-radius: 8px;
    box-shadow: 0 10px 25px rgba(0, 0, 0, 0.3);
    z-index: 9999;
    min-width: 300px;
    max-width: 400px;
    transform: translateX(400px);
    transition: transform 0.3s ease;
    font-family: system-ui, -apple-system, sans-serif;
  `;

  // إضافة الإشعار للصفحة
  document.body.appendChild(notification);

  // إظهار الإشعار
  setTimeout(() => {
    notification.style.transform = 'translateX(0)';
  }, 100);

  // إزالة الإشعار بعد 5 ثواني
  setTimeout(() => {
    notification.style.transform = 'translateX(400px)';
    setTimeout(() => {
      if (notification.parentNode) {
        notification.parentNode.removeChild(notification);
      }
    }, 300);
  }, 5000);

  // إضافة زر الإغلاق
  const closeBtn = notification.querySelector('.notification-close') as HTMLElement;
  if (closeBtn) {
    closeBtn.style.cssText = `
      position: absolute;
      top: 5px;
      right: 10px;
      background: none;
      border: none;
      color: white;
      font-size: 20px;
      cursor: pointer;
      padding: 0;
      width: 24px;
      height: 24px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      transition: background 0.2s;
    `;

    closeBtn.addEventListener('click', () => {
      notification.style.transform = 'translateX(400px)';
      setTimeout(() => {
        if (notification.parentNode) {
          notification.parentNode.removeChild(notification);
        }
      }, 300);
    });

    closeBtn.addEventListener('mouseenter', () => {
      closeBtn.style.background = 'rgba(255, 255, 255, 0.2)';
    });

    closeBtn.addEventListener('mouseleave', () => {
      closeBtn.style.background = 'none';
    });
  }
};

// مكون الإشعارات
const Notifications: React.FC = () => {
  const { state, error } = useAuth();

  useEffect(() => {
    // مراقبة تغييرات تسجيل الدخول
    if (state.isAuthenticated && !state.isLoading) {
      showNotification('تم تسجيل الدخول بنجاح!', 'success');
    }
  }, [state.isAuthenticated, state.isLoading]);

  useEffect(() => {
    // مراقبة الأخطاء
    if (error) {
      showNotification(error, 'error');
    }
  }, [error]);

  return null;
};

// تصدير الدوال للاستخدام في مكونات أخرى
export { showNotification };

export default Notifications;
